@dataclass
class ValidationResult:
    valid_items: List[CartItem]
    total_amount: Decimal
    errors: List[str] = field(default_factory=list)

@dataclass
class DiscountResult:
    discounted_amount: Decimal
    discount_applied: Optional[DiscountCode]
