class CheckoutProcessor:
    def __init__(
        self,
        available_discounts: Dict[str, DiscountCode],
        tax_rates: Dict[str, TaxRate],
        inventory_system: Optional[Dict[str, int]] = None
    ):
        self.available_discounts = available_discounts
        self.tax_rates = tax_rates
        self.inventory_system = inventory_system or {}
        self.order_counter = 0

    def process_checkout(
        self,
        cart_items: List[CartItem],
        user: User,
        discount_code: Optional[str],
        tax_region: str,
        payment_method: PaymentMethod
    ) -> Tuple[bool, Optional[Order], List[str]]:
        all_errors = []

        # Step 1: Validate cart items
        validation_result = self._validate_cart_items(cart_items)
        if validation_result.errors:
            all_errors.extend(validation_result.errors)
            return False, None, all_errors

        # Step 2: Apply discount codes
        discount_result = self._apply_discount(
            validation_result.total_amount,
            discount_code,
            user,
            self.available_discounts
        )
        if discount_result.errors:
            all_errors.extend(discount_result.errors)
            return False, None, all_errors

        # Step 3: Calculate tax
        tax_result = self._calculate_tax(
            discount_result.discounted_amount,
            tax_region
        )
        if tax_result.errors:
            all_errors.extend(tax_result.errors)
            return False, None, all_errors

        # Step 4: Process payment
        payment_result = self._process_payment(
            tax_result.total_with_tax,
            payment_method,
            user
        )
        if not payment_result.success or payment_result.errors:
            all_errors.extend(payment_result.errors)
            return False, None, all_errors

        # Step 5: Create order record
        order = self._create_order(
            user=user,
            items=validation_result.valid_items,
            subtotal=validation_result.total_amount,
            discount_amount=discount_result.original_amount - discount_result.discounted_amount,
            tax_amount=tax_result.tax_amount,
            total_amount=tax_result.total_with_tax,
            transaction_id=payment_result.transaction_id,
            discount_code=discount_code
        )

        return True, order, []

    def _validate_cart_items(self, cart_items: List[CartItem]) -> ValidationResult:
        errors = []
        valid_items = []
        total_amount = Decimal('0')

        if not cart_items:
            errors.append("Cart is empty")
            return ValidationResult(valid_items=[], total_amount=Decimal('0'), errors=errors)

        for item in cart_items:
            if not item.is_available:
                errors.append(f"Item {item.name} (ID: {item.product_id}) is not available")
                continue

            if item.quantity <= 0:
                errors.append(f"Invalid quantity for item {item.name}")
                continue

            if item.price <= 0:
                errors.append(f"Invalid price for item {item.name}")
                continue

            # Check inventory
            if item.product_id in self.inventory_system:
                available_stock = self.inventory_system[item.product_id]
                if item.quantity > available_stock:
                    errors.append(f"Insufficient stock for {item.name}. Available: {available_stock}, Requested: {item.quantity}")
                    continue

            if item.quantity > item.max_stock:
                errors.append(f"Quantity exceeds maximum allowed for {item.name}")
                continue

            valid_items.append(item)
            total_amount += item.price * item.quantity

        if errors:
            return ValidationResult(valid_items=[], total_amount=Decimal('0'), errors=errors)

        return ValidationResult(valid_items=valid_items, total_amount=total_amount, errors=[])

    def _apply_discount(
        self,
        total_amount: Decimal,
        discount_code: Optional[str],
        user: User,
        available_discounts: Dict[str, DiscountCode]
    ) -> DiscountResult:
        errors = []

        if not discount_code:
            return DiscountResult(
                discounted_amount=total_amount,
                discount_applied=None,
                original_amount=total_amount,
                errors=[]
            )

        discount = available_discounts.get(discount_code)

        if not discount:
            errors.append(f"Invalid discount code: {discount_code}")
            return DiscountResult(
                discounted_amount=total_amount,
                discount_applied=None,
                original_amount=total_amount,
                errors=errors
            )

        if not discount.is_active:
            errors.append(f"Discount code {discount_code} is not active")
            return DiscountResult(
                discounted_amount=total_amount,
                discount_applied=None,
                original_amount=total_amount,
                errors=errors
            )

        # Validate user permissions
        if user.tier not in discount.allowed_tiers:
            tier_names = ', '.join([tier.value for tier in discount.allowed_tiers])
            errors.append(
                f"User tier '{user.tier.value}' is not authorized to use discount code '{discount_code}'. "
                f"Allowed tiers: {tier_names}"
            )
            return DiscountResult(
                discounted_amount=total_amount,
                discount_applied=None,
                original_amount=total_amount,
                errors=errors
            )

        # Check minimum purchase amount
        if total_amount < discount.min_purchase_amount:
            errors.append(
                f"Minimum purchase amount of {discount.min_purchase_amount} required for discount code '{discount_code}'. "
                f"Current amount: {total_amount}"
            )
            return DiscountResult(
                discounted_amount=total_amount,
                discount_applied=None,
                original_amount=total_amount,
                errors=errors
            )

        # Calculate discount
        discounted_amount = total_amount
        if discount.discount_type == DiscountType.PERCENTAGE:
            discount_amount = total_amount * (discount.value / Decimal('100'))
            discounted_amount = total_amount - discount_amount
        elif discount.discount_type == DiscountType.FIXED:
            discounted_amount = max(Decimal('0'), total_amount - discount.value)

        return DiscountResult(
            discounted_amount=discounted_amount,
            discount_applied=discount,
            original_amount=total_amount,
            errors=[]
        )

    def _calculate_tax(
        self,
        subtotal: Decimal,
        tax_region: str
    ) -> TaxResult:
        errors = []

        if subtotal < 0:
            errors.append("Invalid subtotal amount")
            return TaxResult(
                subtotal=Decimal('0'),
                tax_amount=Decimal('0'),
                total_with_tax=Decimal('0'),
                tax_rate=Decimal('0'),
                errors=errors
            )

        tax_rate_info = self.tax_rates.get(tax_region)

        if not tax_rate_info:
            errors.append(f"Invalid tax region: {tax_region}")
            return TaxResult(
                subtotal=subtotal,
                tax_amount=Decimal('0'),
                total_with_tax=subtotal,
                tax_rate=Decimal('0'),
                errors=errors
            )

        tax_rate = tax_rate_info.rate
        tax_amount = subtotal * tax_rate
        total_with_tax = subtotal + tax_amount

        return TaxResult(
            subtotal=subtotal,
            tax_amount=tax_amount,
            total_with_tax=total_with_tax,
            tax_rate=tax_rate,
            errors=[]
        )

    def _process_payment(
        self,
        amount: Decimal,
        payment_method: PaymentMethod,
        user: User
    ) -> PaymentResult:
        errors = []

        if amount <= 0:
            errors.append("Invalid payment amount")
            return PaymentResult(
                success=False,
                transaction_id=None,
                amount_charged=Decimal('0'),
                errors=errors
            )

        # Simulate payment processing
        if payment_method.method_type not in ['credit_card', 'debit_card', 'paypal', 'bank_transfer']:
            errors.append(f"Unsupported payment method: {payment_method.method_type}")
            return PaymentResult(
                success=False,
                transaction_id=None,
                amount_charged=Decimal('0'),
                errors=errors
            )

        # Simulate payment validation
        if payment_method.method_type in ['credit_card', 'debit_card']:
            if 'card_number' not in payment_method.details:
                errors.append("Missing card number")
                return PaymentResult(
                    success=False,
                    transaction_id=None,
                    amount_charged=Decimal('0'),
                    errors=errors
                )

        # Generate transaction ID
        transaction_id = f"TXN-{user.user_id}-{datetime.now().strftime('%Y%m%d%H%M%S%f')}"

        return PaymentResult(
            success=True,
            transaction_id=transaction_id,
            amount_charged=amount,
            errors=[]
        )

    def _create_order(
        self,
        user: User,
        items: List[CartItem],
        subtotal: Decimal,
        discount_amount: Decimal,
        tax_amount: Decimal,
        total_amount: Decimal,
        transaction_id: str,
        discount_code: Optional[str]
    ) -> Order:
        self.order_counter += 1
        order_id = f"ORD-{self.order_counter:06d}-{datetime.now().strftime('%Y%m%d')}"

        order = Order(
            order_id=order_id,
            user_id=user.user_id,
            items=items,
            subtotal=subtotal,
            discount_amount=discount_amount,
            tax_amount=tax_amount,
            total_amount=total_amount,
            payment_transaction_id=transaction_id,
            created_at=datetime.now(),
            discount_code=discount_code
        )

        # Update inventory
        for item in items:
            if item.product_id in self.inventory_system:
                self.inventory_system[item.product_id] -= item.quantity

        return order


